import org.opensaml.saml.model.Assertion;
import org.opensaml.saml.model.Response;
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.saml.SAMLAuthenticationProvider;
import org.springframework.security.saml.SAMLBinding;
import org.springframework.security.saml.SAMLResponseDecoder;
import org.springframework.security.saml.SAMLUserDetailsService;
import org.springframework.security.web.authentication.SAMLAuthenticationToken;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RestController;

@SpringBootApplication
@RestController
public class SamlAuthenticationApplication {

    private final SAMLUserDetailsService userDetailsService;
    private final SAMLResponseDecoder samlResponseDecoder;
    private final SAMLAuthenticationProvider samlAuthenticationProvider;

    public SamlAuthenticationApplication(SAMLUserDetailsService userDetailsService, SAMLResponseDecoder samlResponseDecoder, SAMLAuthenticationProvider samlAuthenticationProvider) {
        this.userDetailsService = userDetailsService;
        this.samlResponseDecoder = samlResponseDecoder;
        this.samlAuthenticationProvider = samlAuthenticationProvider;
    }

    @PostMapping("/saml/response")
    public Authentication authenticate(@RequestBody String samlResponse) throws Exception {
        Response samlResponseObject = samlResponseDecoder.decode(samlResponse, SAMLBinding.HTTP_POST);
        Assertion assertion = samlResponseObject.getAssertions().get(0);

        SAMLUserDetails user = userDetailsService.loadUserBySamlResponse(samlResponseObject);
        SAMLAuthenticationToken authenticationToken = new SAMLAuthenticationToken(user, assertion);

        Authentication authentication = samlAuthenticationProvider.authenticate(authenticationToken);
        SecurityContextHolder.getContext().setAuthentication(authentication);

        return authentication;
    }

    public static void main(String[] args) {
        SpringApplication.run(SamlAuthenticationApplication.class, args);
    }
}